def test_search_by_dob_returns_matching_patients():
    auth_token = <get_token_for_clinician('CLIN-003')>
    headers = {'Authorization': f'Bearer {auth_token}'}
    resp = requests.get(
        'http://localhost:8080/Patient',
        params={'birthdate': '1985-06-15'},
        headers=headers
    )
    assert resp.status_code == 200
    bundle = resp.json()
    assert len(bundle.get('entry', [])) == 3
    for entry in bundle['entry']:
        assert entry['resource']['birthDate'] == '1985-06-15'

def test_empty_query_parameter_returns_400():
    auth_token = <get_token_for_clinician('CLIN-001')>
    headers = {'Authorization': f'Bearer {auth_token}'}
    resp = requests.get(
        'http://localhost:8080/Patient',
        headers=headers
    )
    assert resp.status_code in [400, 422]
    outcome = resp.json()
    assert 'issue' in outcome or 'error' in outcome

def test_search_dob_boundary_leap_year():
    auth_token = <get_token_for_clinician('CLIN-001')>
    headers = {'Authorization': f'Bearer {auth_token}'}
    resp = requests.get(
        'http://localhost:8080/Patient',
        params={'birthdate': '2000-02-29'},
        headers=headers
    )
    assert resp.status_code == 200
    bundle = resp.json()
    if len(bundle.get('entry', [])) > 0:
        assert bundle['entry'][0]['resource']['birthDate'] == '2000-02-29'
